import React, { useState } from 'react';
import { aiService } from '../services/aiService';
import { clientService } from '../services';

// Page: Client Finder
// Allows user to input criteria and get 5 potential client leads from Claude.
const ClientFinder = () => {
  const [form, setForm] = useState({ industry: '', companySize: '', region: '', offering: '' });
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSearch = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await aiService.callAI('finder', form);
      setResults(res.data || res);
    } catch (err) {
      console.error(err);
      alert('AI request failed');
    }
    setLoading(false);
  };

  const handleAddToCRM = async (lead) => {
    try {
      // Map the AI lead object into our client schema minimally
      const payload = {
        companyName: lead.company || lead.companyName,
        contactName: lead.contactPerson || lead.contact,
        email: lead.email,
        industry: form.industry || lead.industry,
        status: 'prospect',
        notes: lead.painPoint || '',
        fromAI: true,
        sendWelcomeEmail: true,
      };
      await clientService.createClient(payload);
      alert('Lead added to CRM and welcome email triggered');
    } catch (err) {
      console.error(err);
      alert('Failed to add client');
    }
  };

  return (
    <div>
      <h2>AI Client Finder</h2>
      <form onSubmit={handleSearch}>
        <input name="industry" placeholder="Industry" value={form.industry} onChange={handleChange} />
        <input name="companySize" placeholder="Company size (e.g., 10-50)" value={form.companySize} onChange={handleChange} />
        <input name="region" placeholder="Region" value={form.region} onChange={handleChange} />
        <input name="offering" placeholder="Your service offering" value={form.offering} onChange={handleChange} />
        <button type="submit" disabled={loading}>{loading ? 'Searching...' : 'Find Clients'}</button>
      </form>

      <div style={{ marginTop: 20 }}>
        {results ? (
          <pre style={{ whiteSpace: 'pre-wrap' }}>{typeof results === 'string' ? results : JSON.stringify(results, null, 2)}</pre>
        ) : (
          <p>No results yet.</p>
        )}

        {/* If the AI returned JSON array, render actionable buttons */}
        {Array.isArray(results) && results.map((lead, idx) => (
          <div key={idx} style={{ border: '1px solid #ddd', padding: 10, marginTop: 10 }}>
            <div><strong>{lead.company}</strong> — {lead.contactPerson} ({lead.role})</div>
            <div>{lead.email} • Fit: {lead.fitScore}</div>
            <div>{lead.painPoint}</div>
            <button onClick={() => handleAddToCRM(lead)}>Add to CRM</button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ClientFinder;
